@startuml
class Library {
  +searchBooks(title: String): List
  +sendOverdueEmail(member: Member): void
  +generateMonthlyReport(): PDF
  +addBook(book: Book): void
}

class Book {
  +title: String
  +author: String
  +isbn: String
}

class Member {
  +name: String
  +email: String
  +borrowedBooks: List
}

Library --> Book
Library --> Member
@enduml

@startuml
class Order {
  +id: String
  +total: Float
  +process(): void
}

class PayPalPayment {
  +charge(amount: Float): Boolean
  +refund(amount: Float): Boolean
}

class Receipt {
  +orderId: String
  +amountPaid: Float
  +print(): void
}

Order --> PayPalPayment
Order --> Receipt
@enduml

@startuml
class Cat {
  +name: String
  +speak(): String
  +purr(): void
}

class Dog {
  +name: String
  +speak(): String
  +fetch(): void
}

class ZooKeeper {
  +feed(animal: Cat): void
}

Dog --|> Cat
@enduml
